#include <stdio.h>
#include <string.h>
#define MOD 1000000007LL
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        char s[100005]; scanf("%s", s);
        long long cnt[26] = {0};
        for(int i=0;i<N;i++) cnt[s[i]-'a']++;
        long long ans = 1;
        for(int i=0;i<26;i++) ans = ans * (cnt[i] + 1) % MOD;
        ans = (ans - 1 + MOD) % MOD;
        printf("%lld\n", ans);
    }
    return 0;
}

