const fs = require('fs');
const data = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const MOD = 1000000007n;
const T = Number(data[idx++]);
let results = [];
for (let t = 0; t < T; t++) {
  const N = Number(data[idx++]);
  const s = data[idx++];
  const cnt = new Array(26).fill(0n);
  for (let i = 0; i < N; i++) {
    cnt[s.charCodeAt(i) - 97]++;
  }
  let ans = 1n;
  for (let i = 0; i < 26; i++) {
    ans = (ans * (cnt[i] + 1n)) % MOD;
  }
  ans = (ans - 1n + MOD) % MOD;
  results.push(ans.toString());
}
console.log(results.join('\n'));

